import sys

def main():
    s = sys.stdin.readline().strip()
    # 여는 콤보 'A'를 세고 닫는 콤보 'D'로 상쇄한다
    open_cnt = 0
    ok = True
    for c in s:
        if c == 'A':
            open_cnt += 1
        else:
            open_cnt -= 1
        if open_cnt < 0:
            ok = False
            break
    print("true" if ok and open_cnt == 0 else "false")

if __name__ == "__main__":
    main()

