const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const n = Number(input[0]);
    let idx = 1;
    const entered = [];
    for (let i = 0; i < n; i++) entered.push(input[idx++]);
    const m = Number(input[idx++]);
    const returned = [];
    for (let i = 0; i < m; i++) returned.push(input[idx++]);
    // 입장 닉네임 개수를 세고 귀환한 만큼 빼서 남은 인원을 사전순으로 출력한다
    const cnt = new Map();
    for (const p of entered) cnt.set(p, (cnt.get(p) || 0) + 1);
    for (const p of returned) cnt.set(p, cnt.get(p) - 1);
    const missing = [];
    for (const [name, c] of cnt)
        for (let i = 0; i < c; i++) missing.push(name);
    missing.sort();
    console.log(missing.join(' '));
}

main();

