const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const n = Number(input[0]);
    const answers = input[1].split(' ').map(Number);
    // 네 NPC의 찍기 패턴을 주기로 돌려 채점한다
    const p1 = [3, 1, 2, 4, 5];
    const p2 = [1, 3, 1, 5];
    const p3 = [5, 5, 2, 2, 4, 4];
    const p4 = [2, 4, 2, 4, 1, 3, 5];
    const score = [0, 0, 0, 0];
    for (let i = 0; i < n; i++) {
        if (answers[i] === p1[i % 5]) score[0]++;
        if (answers[i] === p2[i % 4]) score[1]++;
        if (answers[i] === p3[i % 6]) score[2]++;
        if (answers[i] === p4[i % 7]) score[3]++;
    }
    const max = Math.max(...score);
    const res = [];
    for (let i = 0; i < 4; i++) if (score[i] === max) res.push(i + 1);
    console.log(res.join(' '));
}

main();

