import sys

def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    lost = list(map(int, data[1].split())) if len(data) > 1 and data[1].split() else []
    reserve = list(map(int, data[2].split())) if len(data) > 2 and data[2].split() else []
    # 학생별 보유 개수 배열을 만들고 앞에서부터 그리디하게 빌려준다
    cnt = [0] * (n + 2)
    for i in range(1, n + 1):
        cnt[i] = 1
    for r in reserve:
        cnt[r] += 1
    for l in lost:
        cnt[l] -= 1
    for i in range(1, n + 1):
        if cnt[i] != 0:
            continue
        if i - 1 >= 1 and cnt[i - 1] == 2:
            cnt[i - 1] -= 1
            cnt[i] += 1
    count = 0
    for i in range(1, n + 1):
        if cnt[i] >= 1:
            count += 1
    print(count)

if __name__ == "__main__":
    main()

