const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const n = Number(input[0]);
    const lost = (input[1] || '').split(' ').filter(x => x !== '').map(Number);
    const reserve = (input[2] || '').split(' ').filter(x => x !== '').map(Number);
    // 도난과 여분을 반영한 뒤 앞에서부터 그리디하게 빌려준다
    const cnt = new Array(n + 2).fill(0);
    for (let i = 1; i <= n; i++) cnt[i] = 1;
    for (const r of reserve) cnt[r]++;
    for (const l of lost) cnt[l]--;
    for (let i = 1; i <= n; i++) {
        if (cnt[i] !== 0) continue;
        if (i - 1 >= 1 && cnt[i - 1] === 2) { cnt[i - 1]--; cnt[i]++; }
    }
    let count = 0;
    for (let i = 1; i <= n; i++) if (cnt[i] >= 1) count++;
    console.log(count);
}

main();

