const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const first = input[0].split(' ');
    const n = Number(first[0]), K = Number(first[1]);
    const scoville = input[1].split(' ').map(Number);
    // 최소 힙으로 매번 가장 약한 두 포션을 합친다
    const heap = [];
    const push = (v) => {
        heap.push(v);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p] <= heap[i]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            const len = heap.length;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, s = i;
                if (l < len && heap[l] < heap[s]) s = l;
                if (r < len && heap[r] < heap[s]) s = r;
                if (s === i) break;
                [heap[s], heap[i]] = [heap[i], heap[s]];
                i = s;
            }
        }
        return top;
    };
    for (const v of scoville) push(v);
    let count = 0;
    while (heap[0] < K) {
        if (heap.length < 2) { console.log(-1); return; }
        const x = pop();
        const y = pop();
        push(x + y);
        count++;
    }
    console.log(count);
}

main();

