const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const [n, m] = input[0].split(' ').map(Number);
    const map = [];
    for (let i = 0; i < n; i++) {
        const row = input[1 + i];
        const line = new Array(m);
        for (let j = 0; j < m; j++) line[j] = row[j] === '.' ? 1 : 0;
        map.push(line);
    }
    // BFS로 (0,0)에서 (n-1,m-1)까지 최단 거리를 구한다
    const dx = [-1, 1, 0, 0];
    const dy = [0, 0, -1, 1];
    const dist = Array.from({ length: n }, () => new Array(m).fill(0));
    const q = [[0, 0]];
    let head = 0;
    dist[0][0] = 1; // 시작 칸 포함 거리 1
    while (head < q.length) {
        const [x, y] = q[head++];
        for (let d = 0; d < 4; d++) {
            const nx = x + dx[d], ny = y + dy[d];
            if (nx < 0 || nx >= n || ny < 0 || ny >= m) continue;
            if (map[nx][ny] === 0 || dist[nx][ny] !== 0) continue;
            dist[nx][ny] = dist[x][y] + 1; // 큐에 넣을 때 거리 확정
            q.push([nx, ny]);
        }
    }
    console.log(dist[n - 1][m - 1] === 0 ? -1 : dist[n - 1][m - 1] - 1);
}

main();

