function main() {
    const [n, m] = input[0].split(' ').map(Number);
    const adj = Array.from({ length: n + 1 }, () => []);
    for (let i = 0; i < m; i++) {
        const t = input[1 + i].split(' ').map(Number);
        const u = t[0], v = t[1], w = t[2];
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }
    const se = input[1 + m].split(' ').map(Number);
    const s = se[0], e = se[1];
    // 최소 힙 다익스트라. 거리는 Number(가중치 합 ~ 1e9 * 1000)
    const INF = Infinity;
    const dist = new Array(n + 1).fill(INF);
    dist[s] = 0;
    // [거리, 정점] 쌍을 담는 이진 최소 힙
    const heap = [];
    const push = (d, node) => {
        heap.push([d, node]);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] <= heap[i][0]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, sm = i;
                if (l < heap.length && heap[l][0] < heap[sm][0]) sm = l;
                if (r < heap.length && heap[r][0] < heap[sm][0]) sm = r;
                if (sm === i) break;
                [heap[sm], heap[i]] = [heap[i], heap[sm]];
                i = sm;
            }
        }
        return top;
    };
    push(0, s);
    while (heap.length > 0) {
        const [d, u] = pop();
        if (d > dist[u]) continue;
        for (const [to, w] of adj[u]) {
            if (dist[u] + w < dist[to]) {
                dist[to] = dist[u] + w;
                push(dist[to], to);
            }
        }
    }
    console.log(dist[e] === INF ? -1 : dist[e]);
}

