const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const [n, m] = input[0].split(' ').map(Number);
    const cost = [];
    for (let i = 0; i < n; i++) {
        const row = input[1 + i];
        const line = new Array(m);
        for (let j = 0; j < m; j++) line[j] = row.charCodeAt(j) - 48;
        cost.push(line);
    }
    // 칸마다 비용이 달라 최소 힙 다익스트라로 마나 합 최소를 구한다
    const INF = Infinity;
    const dist = Array.from({ length: n }, () => new Array(m).fill(INF));
    // [거리, 행, 열]을 담는 이진 최소 힙
    const heap = [];
    const push = (d, r, c) => {
        heap.push([d, r, c]);
        let i = heap.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (heap[p][0] <= heap[i][0]) break;
            [heap[p], heap[i]] = [heap[i], heap[p]];
            i = p;
        }
    };
    const pop = () => {
        const top = heap[0];
        const last = heap.pop();
        if (heap.length > 0) {
            heap[0] = last;
            let i = 0;
            while (true) {
                let l = 2 * i + 1, r = 2 * i + 2, sm = i;
                if (l < heap.length && heap[l][0] < heap[sm][0]) sm = l;
                if (r < heap.length && heap[r][0] < heap[sm][0]) sm = r;
                if (sm === i) break;
                [heap[sm], heap[i]] = [heap[i], heap[sm]];
                i = sm;
            }
        }
        return top;
    };
    dist[0][0] = cost[0][0];
    push(dist[0][0], 0, 0);
    const dr = [-1, 1, 0, 0], dc = [0, 0, -1, 1];
    while (heap.length > 0) {
        const [d, r, c] = pop();
        if (d > dist[r][c]) continue;
        for (let k = 0; k < 4; k++) {
            const nr = r + dr[k], nc = c + dc[k];
            if (nr < 0 || nc < 0 || nr >= n || nc >= m) continue;
