def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    g = []
    for i in range(n):
        g.append(list(map(int, data[1 + i].split())))
    parent = list(range(n))

    def find(x):
        # 경로 압축(반복형)
        root = x
        while parent[root] != root:
            root = parent[root]
        while parent[x] != root:
            parent[x], x = root, parent[x]
        return root

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb

    for i in range(n):
        for j in range(n):
            if g[i][j] == 1:
                union(i, j)
    # 루트 개수 = 동맹 세력 수
    count = sum(1 for i in range(n) if find(i) == i)
    print(count)

