    for (let i = 1; i <= n; i++) if (indeg[i] === 0) push(i);
    const order = [];
    while (heap.length > 0) {
        const u = pop();
        order.push(u);
        for (const v of adj[u]) if (--indeg[v] === 0) push(v);
    }
    if (order.length < n) console.log(-1);
    else console.log(order.join(' '));
}

main();

