    function gcd(x, y) {
        while (y !== 0) { const t = x % y; x = y; y = t; }
        return x;
    }
    let g = a[0], l = a[0];
    for (let i = 1; i < n; i++) {
        g = gcd(g, a[i]);
        l = l / gcd(l, a[i]) * a[i];
    }
    console.log(g + ' ' + l);
}

