const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const [n, m] = input[0].split(' ').map(Number);
    const e = [];
    for (let i = 0; i < m; i++) {
        const [u, v, w] = input[1 + i].split(' ').map(Number);
        e.push([w, u, v]);
    }
    // 간선을 비용순으로 정렬한 뒤 Union-Find 크루스칼로 최소 신장 트리 비용을 구한다
    e.sort((x, y) => x[0] - y[0]);
    const par = new Array(n + 1);
    for (let i = 0; i <= n; i++) par[i] = i;
    const find = (x) => {
        while (par[x] !== x) { par[x] = par[par[x]]; x = par[x]; }
        return x;
    };
    let total = 0, used = 0;
    for (const [w, u, v] of e) {
        const ru = find(u), rv = find(v);
        if (ru !== rv) {
            par[ru] = rv;
            total += w;
            if (++used === n - 1) break;
        }
    }
    console.log(total);
}

main();

