const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const seq = input[0].split(' ');
    const hand = input[1].trim();
    // 키패드 위 행과 열을 좌표로 환산한다
    const row = (d) => d === 0 ? 3 : Math.floor((d - 1) / 3);
    const col = (d) => d === 0 ? 1 : (d - 1) % 3;
    let lr = 3, lc = 0, rr = 3, rc = 2;
    let res = '';
    for (const t of seq) {
        const d = Number(t);
        if (d === 1 || d === 4 || d === 7) { res += 'L'; lr = row(d); lc = col(d); }
        else if (d === 3 || d === 6 || d === 9) { res += 'R'; rr = row(d); rc = col(d); }
        else {
            const dr = row(d), dc = col(d);
            const dl = Math.abs(lr - dr) + Math.abs(lc - dc);
            const dR = Math.abs(rr - dr) + Math.abs(rc - dc);
            if (dl < dR) { res += 'L'; lr = dr; lc = dc; }
            else if (dR < dl) { res += 'R'; rr = dr; rc = dc; }
            else if (hand === 'right') { res += 'R'; rr = dr; rc = dc; }
            else { res += 'L'; lr = dr; lc = dc; }
        }
    }
    console.log(res);
}

main();

