const input = require('fs').readFileSync(0, 'utf8').trim().split('\n');

function main() {
    const n = Number(input[0]);
    const g = [];
    for (let i = 0; i < n; i++) g.push(input[1 + i].trim());
    // 방문하지 않은 땅에서 BFS로 연결된 섬을 묶고 크기를 모은다
    const vis = Array.from({ length: n }, () => new Array(n).fill(false));
    const dx = [1, -1, 0, 0], dy = [0, 0, 1, -1];
    const sizes = [];
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (g[i][j] === '1' && !vis[i][j]) {
                let cnt = 0;
                const q = [i * n + j];
                vis[i][j] = true;
                let head = 0;
                while (head < q.length) {
                    const cur = q[head++];
                    const x = Math.floor(cur / n), y = cur % n;
                    cnt++;
                    for (let d = 0; d < 4; d++) {
                        const nx = x + dx[d], ny = y + dy[d];
                        if (nx >= 0 && nx < n && ny >= 0 && ny < n && !vis[nx][ny] && g[nx][ny] === '1') {
                            vis[nx][ny] = true;
                            q.push(nx * n + ny);
                        }
                    }
                }
                sizes.push(cnt);
            }
        }
    }
    sizes.sort((a, b) => a - b);
    console.log([sizes.length, ...sizes].join('\n'));
}

main();

