else {
  let num = 1n, den = 1n;
  for (let i = 0; i < r; i++) { num = num * BigInt(n - i) % MOD; den = den * BigInt(i + 1) % MOD; }
  console.log((num * pm(den, MOD - 2n) % MOD).toString());
}
